mapper.select:
select suu.user_id, suu.username, suu.name, suu.email, suu.mobile, suu.type, suu.status, suu.create_time, suu.dept_id, sd.name as deptName, LISTAGG(sr.role_name,',') as roleName from sys_user suu left join sys_dept sd on suu.dept_id=sd.dept_id left join sys_user_role sur on suu.user_id=sur.user_id left join sys_role sr on sur.role_id=sr.role_id
AND (suu.username LIKE concat('%',#{username},'%') or suu.name LIKE concat('%',#{username},'%'))
AND suu.type = #{type}
AND sr.role_id = #{roleId}
AND suu.user_id in
#{userId}
and suu.dept_id in ( SELECT dept_id from sys_dept where del_flag = 0 and path like (select '%$' || dept_id || '$%' from sys_user u where user_id = #{userId}))
and suu.dept_id in (SELECT dept_id from sys_dept where del_flag = 0 and path like '%$'|| #{deptId} || '$%')
group by suu.user_id, suu.username, suu.name, suu.email, suu.mobile, suu.type, suu.status, suu.create_time, suu.dept_id, sd.name order by suu.status desc,suu.create_time DESC
